    weekly_signal = get_macd_signal(stock_data['weekly'])
    monthly_trend = get_trend(stock_data['monthly'])

    if daily_signal == 'BUY' and weekly_signal == 'BUY' and monthly_trend == 'UP':
        return {'confirmation': 'STRONG_BUY', 'bonus': 20}
    elif daily_signal == 'BUY' and weekly_signal == 'BUY':
