stock_picker_integrations.3. smart_entry_threshold:
def calculate_adaptive_threshold(cash_ratio, recent_winrate, concentration):
    """智能動態入場門檻"""

    base = 60

    # 現金比例調整
    if cash_ratio > 0.95:
        adjust = -25  # 極端現金: 35分
    elif cash_ratio > 0.75:
        adjust = -10  # 高現金: 50分
    else:
        adjust = 0    # 正常: 60分

    # 胜率調整
    if recent_winrate < 0.50:
        adjust += 15  # 低胜率: +75分保守
    elif recent_winrate >= 0.65:
        adjust -= 5   # 高胜率: -5分激進

    # 集中度調整
    if concentration > 0.30:
        adjust += 10  # 高風險: +70分

    return base + adjust

stock_picker_integrations.5. dynamic_takeprofit:
def get_takeprofit_plan(entry_price, volatility_level='normal'):
    """梯度止盈計劃"""

    plans = [
        {'target': entry_price * 1.05, 'sell_pct': 0.40, 'desc': '+5%賣40%'},
        {'target': entry_price * 1.10, 'sell_pct': 0.30, 'desc': '+10%賣30%'},
        {'target': entry_price * 1.15, 'sell_pct': 0.30, 'desc': '+15%清倉'}
    ]

    # 波動率調整 (±20%)
    if volatility_level == 'high':
        plans = [{'target': p['target'] * 1.2, **{k:v for k,v in p.items() if k != 'target'}} for p in plans]
    elif volatility_level == 'low':
        plans = [{'target': p['target'] * 0.8, **{k:v for k,v in p.items() if k != 'target'}} for p in plans]

    return plans
